.PHONY: dev build test lint fmt clean help

help:
	@echo "Available commands:"
	@echo "  make dev          - Start development server with hot reload (go run)"
	@echo "  make build        - Build binary"
	@echo "  make test         - Run tests"
	@echo "  make lint         - Run linter"
	@echo "  make fmt          - Format code"
	@echo "  make clean        - Remove build artifacts"

dev:
	go run main.go

build:
	go build -o bin/api

test:
	go test ./...

lint:
	golangci-lint run

fmt:
	go fmt ./...

clean:
	rm -rf bin/ tmp/

